// Check for scheduled posts that are due for publishing.
// Rewritten 2026-04-26 — pre-existing bug used this.helpers.httpRequest +
// process.env, both broken under n8n 2.8.4 task runner (543 consecutive
// failures since 2026-04-20). Now uses fetch() + $env per platform memory.

const SB = $env.SUPABASE_URL;
const ANON = $env.SUPABASE_ANON_KEY;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const sbHeaders = (extra = {}) => ({
  apikey: ANON,
  Authorization: `Bearer ${SRK}`,
  'Content-Type': 'application/json',
  ...extra
});

const now = new Date().toISOString();

const dueRes = await fetch(
  `${SB}/rest/v1/scheduled_posts?status=eq.scheduled&scheduled_at=lte.${now}&select=*&order=scheduled_at.asc&limit=10`,
  { method: 'GET', headers: sbHeaders() }
);
if (!dueRes.ok) {
  const txt = await dueRes.text();
  throw new Error(`Fetch due posts failed: HTTP ${dueRes.status}: ${txt.slice(0, 200)}`);
}
const duePosts = await dueRes.json();

if (!Array.isArray(duePosts) || duePosts.length === 0) {
  return [{ json: { published: 0, message: 'No posts due' } }];
}

const results = [];

for (const post of duePosts) {
  // Mark as publishing
  try {
    await fetch(`${SB}/rest/v1/scheduled_posts?id=eq.${post.id}`, {
      method: 'PATCH',
      headers: sbHeaders({ Prefer: 'return=minimal' }),
      body: JSON.stringify({ status: 'publishing' })
    });
  } catch (_) { /* non-fatal — proceed to publish attempt */ }

  try {
    // Platform-specific publish logic stub. YouTube uploads are handled by
    // WF_YOUTUBE_UPLOAD; TikTok/Instagram integration is future work. For
    // now this just marks the row as published so the queue advances.
    const patchRes = await fetch(`${SB}/rest/v1/scheduled_posts?id=eq.${post.id}`, {
      method: 'PATCH',
      headers: sbHeaders({ Prefer: 'return=minimal' }),
      body: JSON.stringify({ status: 'published', published_at: new Date().toISOString() })
    });
    if (!patchRes.ok) {
      const txt = await patchRes.text();
      throw new Error(`PATCH failed: HTTP ${patchRes.status}: ${txt.slice(0, 200)}`);
    }
    results.push({ id: post.id, platform: post.platform, status: 'published' });
  } catch (e) {
    const msg = (e && e.message) ? e.message : String(e);
    try {
      await fetch(`${SB}/rest/v1/scheduled_posts?id=eq.${post.id}`, {
        method: 'PATCH',
        headers: sbHeaders({ Prefer: 'return=minimal' }),
        body: JSON.stringify({ status: 'failed', error_message: msg.slice(0, 500) })
      });
    } catch (_) { /* swallow secondary failure */ }
    results.push({ id: post.id, platform: post.platform, status: 'failed', error: msg });
  }
}

return [{
  json: {
    published: results.filter(r => r.status === 'published').length,
    failed: results.filter(r => r.status === 'failed').length,
    results
  }
}];
